#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int costs[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &costs[i]);
    }
    int dp1[N], dp2[N];
    dp1[0] = costs[0];
    dp2[0] = 0;
    for (int i = 1; i < N; i++) {
        dp1[i] = dp2[i-1] + costs[i];
        dp2[i] = (dp1[i-1] <= dp2[i-1]) ? dp1[i-1] : dp2[i-1];
    }
    int ans = (dp1[N-1] <= dp2[N-1]) ? dp1[N-1] : dp2[N-1];
    if (N > 1) {
        ans = (dp1[N-1] <= dp1[0] + dp2[N-1]) ? dp1[N-1] : dp1[0] + dp2[N-1];
    }
    printf("%d\n", ans);
    return 0;
}

