        dp2[0] = 0;
        for (int i = 1; i < N; i++) {
            dp1[i] = dp2[i-1] + costs[i];
            dp2[i] = (dp1[i-1] <= dp2[i-1]) ? dp1[i-1] : dp2[i-1];
        }
        int ans = (dp1[N-1] <= dp2[N-1]) ? dp1[N-1] : dp2[N-1];
        if (N > 1) {
            ans = (dp1[N-1] <= dp1[0] + dp2[N-1]) ? dp1[N-1] : dp1[0] + dp2[N-1];
