const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const N = parseInt(readline());
const costs = readline().split(' ').map(Number);
const dp1 = new Array(N).fill(0);
const dp2 = new Array(N).fill(0);
dp1[0] = costs[0];
dp2[0] = 0;
for (let i = 1; i < N; i++) {
    dp1[i] = dp2[i-1] + costs[i];
    dp2[i] = Math.min(dp1[i-1], dp2[i-1]);
}
let ans = Math.min(dp1[N-1], dp2[N-1]);
if (N > 1) {
    ans = Math.min(ans, dp1[0] + dp2[N-1]);
}
console.log(ans);
